UPDATE supp_rqst
SET sr_status_cd = #{srStatusCd},
    sr_submit_dt = SYSDATE,
    sr_submit_cn = #{srSubmitCn}
WHERE sr_ref_biz_cd = #{srRefBizCd}
  AND sr_ref_no = #{irNo}
  AND receiver_id = #{irOwrId}
  AND sr_status_cd = #{beforeSrStatusCd}

UPDATE imp_rqst
SET ir_status_cd = #{irStatusCd}
WHERE ir_no = #{irNo}
  AND ir_owr_id = #{irOwrId}
  AND ir_status_cd = #{beforeIrStatusCd}
